import{_ as a,c as s,o as e,a1 as t}from"./chunks/framework.biRBrEtS.js";const f=JSON.parse('{"title":"FAQ","description":"","frontmatter":{},"headers":[],"relativePath":"zh-CN/guide/faq.md","filePath":"zh-CN/guide/faq.md","lastUpdated":1714705517000}'),i={name:"zh-CN/guide/faq.md"},l=t('<h1 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h1><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><details class="details custom-block"><summary>调用接口报404</summary><p>目前没有支持全部的onebot规范接口，请检查是否调用了不支持的接口</p></details><details class="details custom-block"><summary>如何使用CQ码</summary><p>将消息上报类型格式更改从消息段为CQ码即可</p></details><details class="details custom-block"><summary>二维码无法扫描</summary><p>NapCat 会自动保存二维码到目录，可以手动打开图片扫描</p><p>如果没有条件访问本地目录，可以将二维码解析的 url 复制到二维码生成网站上生成二维码，然后手机QQ扫描</p></details><details class="details custom-block"><summary>语音、视频发送失败</summary><p>需要 配置 ffmpeg 路径, <a href="/zh-CN/guide/ffmpeg">ffmpeg 下载地址</a></p><p>将 ffmpeg 目录加入环境变量，如果仍未生效，可以修改 napcat 启动脚本加入 FFMPEG_PATH 变量指定到 ffmpeg程序的完整路径</p><p>如 Windows 上修改 napcat.ps1，在第一行加入</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">env:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">FFMPEG_PATH</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;d:\\ffmpeg\\bin\\ffmpeg.exe&quot;</span></span></code></pre></div></details><details class="details custom-block"><summary>Windows系统出现QQ本体界面?</summary><p>尝试管理员启动NapCat即可，如果失败请反馈NapCat开发群</p></details><details class="details custom-block"><summary>出现 error code v2:-1 之类的提示</summary><p>不用管，这是正常现象，是因为 QQ 本身的问题，不影响使用</p></details><details class="details custom-block"><summary>登录提示出现网络环境不稳定不在同一网络</summary><p>如果在服务器扫码登录提示出现网络环境不稳定不在同一网络，可以尝试在本地登录后，将 QQ 的文档传到服务器相同目录覆盖，Linux 目录位于 <code>~/.config/QQ</code>, Windows 一般是 <strong>文档下的QQ文件夹</strong>，具体可以打开 <code>QQ的设置-&gt;存储管理</code> 查看</p><p>或者手机使用 VPN 等方式连接到服务器网络使其和服务器在同一网络</p></details><details class="details custom-block"><summary>Windows 运行出现 sqlite3 不是 win32 程序</summary><p>运行时出现<code>node_sqlite3.node is not a valid Win32 application</code></p><p>检查下载的是否是 Windows 版本的 NapCatQQ</p><p>检查是否是安装的 64 位版本的 QQ</p></details><details class="details custom-block"><summary>如果出现崩溃</summary><p>由于新版本使用了 Native Hook，如果你的 NapCatQQ 崩溃了，尝试删除 <code>MoeHoo-xxxx.node</code></p></details>',11),o=[l];function d(p,c,m,n,r,u){return e(),s("div",null,o)}const k=a(i,[["render",d]]);export{f as __pageData,k as default};
